// instrumentedHandler wraps HTTP handlers with per-user metric tracking
func instrumentedHandler(endpoint string, handler func(http.ResponseWriter, *http.Request)) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		method := r.Method

		// Track active requests
		activeRequests.WithLabelValues(userID).Inc()
		defer activeRequests.WithLabelValues(userID).Dec()

		// Track request size
		requestSize.WithLabelValues(userID, endpoint).Observe(float64(r.ContentLength))

		// Time the request
		start := time.Now()

		// Use a response writer wrapper to capture status code and response size
		rw := &responseWriterWrapper{ResponseWriter: w, statusCode: http.StatusOK}

		handler(rw, r)

		duration := time.Since(start).Seconds()
		statusCode := fmt.Sprintf("%d", rw.statusCode)

		// Record metrics
		httpRequestsTotal.WithLabelValues(userID, method, endpoint, statusCode).Inc()
		httpRequestDuration.WithLabelValues(userID, method, endpoint).Observe(duration)
		responseSize.WithLabelValues(userID, endpoint).Observe(float64(rw.bytesWritten))

		// Track errors
		if rw.statusCode >= 400 {
			errorType := "client_error"
			if rw.statusCode >= 500 {
				errorType = "server_error"
			}
			errorTotal.WithLabelValues(userID, endpoint, errorType).Inc()
		}
	}
}

type responseWriterWrapper struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriterWrapper) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriterWrapper) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

// trackOperation records latency of an internal operation for a specific user
func trackOperation(userID, operation string, f func() error) error {
	start := time.Now()
	err := f()
	duration := time.Since(start).Seconds()

	status := "success"
	if err != nil {
		status = "error"
	}

	operationLatency.WithLabelValues(userID, operation, status).Observe(duration)
	return err
}

// trackFeature records feature usage for a specific user
func trackFeature(userID, feature, plan string) {
	featureUsage.WithLabelValues(userID, feature, plan).Inc()
}

