// simulateTraffic generates synthetic traffic for demo purposes
func simulateTraffic() {
	users := []string{"user-1001", "user-1002", "user-1003", "user-2001", "user-2002", "admin-01"}
	plans := []string{"free", "pro", "enterprise", "free", "pro", "enterprise"}
	endpoints := []string{"/api/data", "/api/search", "/api/upload"}

	client := &http.Client{Timeout: 5 * time.Second}

	for {
		idx := rand.Intn(len(users))
		userID := users[idx]
		plan := plans[idx]
		endpoint := endpoints[rand.Intn(len(endpoints))]

		url := fmt.Sprintf("http://localhost:8080%s?user_id=%s&plan=%s", endpoint, userID, plan)
		if endpoint == "/api/search" {
			queries := []string{"golang", "prometheus", "metrics", "observability", ""}
			url += "&q=" + queries[rand.Intn(len(queries))]
		}

		req, err := http.NewRequest("GET", url, nil)
		if err != nil {
			continue
		}
		req.Header.Set("X-User-ID", userID)

		resp, err := client.Do(req)
		if err == nil {
			resp.Body.Close()
		}

		time.Sleep(time.Duration(100+rand.Intn(400)) * time.Millisecond)
	}
}

